1	/**
2	 * Text utilities for bot adapters: argument parsing, platform character
3	 * limits, single-message truncation, and multi-message chunking.
4	 *
5	 * These live in their own module (rather than the `index.ts` barrel) so that
6	 * sibling modules like `streaming.ts` can import them directly without creating
7	 * a barrel <-> module import cycle.
8	 */
9	
10	/**
11	 * Parses whitespace-separated text into a subcommand and remaining args.
12	 * Used by Slack and Telegram command handlers where input is plain text.
13	 *
14	 * @param text - Raw command text.
15	 * @param skipFirst - If true, skips the first token (e.g. for Telegram where the command name is included).
16	 * @returns The parsed subcommand (defaults to "list") and remaining args.
17	 */
18	export function parseTextArgs(
19	  text: string,
20	  skipFirst = false,
21	): { subcommand: string; args: string[] } {
22	  const parts = text.trim().split(/\s+/);
23	  const tokens = skipFirst ? parts.slice(1) : parts;
24	  return { subcommand: tokens[0] || "list", args: tokens.slice(1) };
25	}
26	
27	/** Text-platform commands whose first token selects a subcommand. */
28	const SUBCOMMAND_COMMANDS = new Set(["todo", "workflow"]);
29	
30	/**
31	 * Builds the args object for a text-platform command dispatch.
32	 *
33	 * For commands that take a subcommand (`todo`, `workflow`) it lifts the first
34	 * token of `rawText` into `args.subcommand`; every other command gets an empty
35	 * args object. Shared by the Slack, Telegram and WhatsApp adapters so the
36	 * subcommand rule lives in one place instead of an inline `if` in each.
37	 */
38	export function extractSubcommandArgs(
39	  commandName: string,
40	  rawText: string | undefined,
41	): Record<string, string | number | boolean | undefined> {
42	  if (!SUBCOMMAND_COMMANDS.has(commandName)) return {};
43	  return { subcommand: parseTextArgs(rawText ?? "").subcommand };
44	}
45	
46	/** Per-platform message character limits. Used by truncateResponse. */
47	export const PLATFORM_LIMITS: Record<string, number> = {
48	  discord: 2000,
49	  slack: 4000,
50	  telegram: 4096,
51	  whatsapp: 4096,
52	};
53	
54	/**
55	 * Truncates a response message to fit within the platform's character limit.
56	 * Truncates at word boundaries and optionally appends a web app link.
57	 *
58	 * @param text - The message text to truncate.
59	 * @param platform - The target platform (discord, slack, telegram, whatsapp).
60	 * @param conversationUrl - Optional URL to the full conversation on the web app.
61	 * @returns The truncated message.
62	 */
63	export function truncateResponse(
64	  text: string,
65	  platform: "discord" | "slack" | "telegram" | "whatsapp",
66	  conversationUrl?: string,
67	): string {
68	  const limit = PLATFORM_LIMITS[platform];
69	  if (text.length <= limit) {
70	    return text;
71	  }
72	
73	  const suffix = conversationUrl
74	    ? `\n\n[View full response](${conversationUrl})`
75	    : "\n\n... (truncated)";
76	  const maxLen = limit - suffix.length;
77	
78	  // Truncate at word boundary, avoiding cuts inside markdown links
79	  let truncated = text.slice(0, maxLen);
80	  const lastSpace = truncated.lastIndexOf(" ");
81	  if (lastSpace > maxLen * 0.8) {
82	    truncated = truncated.slice(0, lastSpace);
83	  }
84	
85	  // If we cut inside a markdown link [label](url), backtrack to before the link
86	  const lastOpenBracket = truncated.lastIndexOf("[");
87	  if (lastOpenBracket > -1) {
88	    const closeParen = text.indexOf(")", lastOpenBracket);
89	    if (closeParen > -1 && closeParen > truncated.length) {
90	      // We're inside an incomplete link — backtrack to before it
91	      const beforeLink = truncated.lastIndexOf("\n", lastOpenBracket);
92	      if (beforeLink > maxLen * 0.5) {
93	        truncated = truncated.slice(0, beforeLink);
94	      }
95	    }
96	  }
97	
98	  return truncated + suffix;
99	}
100	
101	/**
102	 * Returns true if cutting ``text`` at index ``idx`` would land inside an
103	 * incomplete markdown link of the form ``[label](url)``. Used by
104	 * {@link chunkResponse} to walk the cut boundary back to before the link so
105	 * we never deliver a half-rendered link to the user.
106	 */
107	function cutsInsideMarkdownLink(text: string, idx: number): boolean {
108	  const lastOpenBracket = text.lastIndexOf("[", idx - 1);
109	  if (lastOpenBracket === -1) return false;
110	  // If a `]` appears between `[` and idx the bracket is already closed.
111	  if (text.lastIndexOf("]", idx - 1) > lastOpenBracket) {
112	    // Bracket closed — but if `(` follows immediately, the URL portion may
113	    // still be open at idx. Check for an unclosed `(` to the left of idx.
114	    const lastOpenParen = text.lastIndexOf("(", idx - 1);
115	    const lastCloseParen = text.lastIndexOf(")", idx - 1);
116	    if (lastOpenParen > lastCloseParen) {
117	      const closeAfter = text.indexOf(")", idx);
118	      return closeAfter !== -1;
119	    }
120	    return false;
121	  }
122	  // Bracket is still open at idx — definitely inside a link.
123	  const closeParen = text.indexOf(")", lastOpenBracket);
124	  return closeParen !== -1;
125	}
126	
127	/**
128	 * Strips fenced code blocks (``` ... ```) so the parity checks only see
129	 * narrative text. Code can legitimately contain ``**`` (Python ``**kwargs``),
130	 * lone ``*`` (shell globs ``*.txt``), or stray backticks, and those bytes
131	 * must not poison emphasis parity for prose.
132	 */
133	function stripFencedBlocks(s: string): string {
134	  let out = "";
135	  let inFence = false;
136	  let i = 0;
137	  while (i < s.length) {
138	    if (s.startsWith("```", i)) {
139	      inFence = !inFence;
140	      i += 3;
141	      continue;
142	    }
143	    if (!inFence) out += s[i];
144	    i++;
145	  }
146	  return out;
147	}
148	
149	/**
150	 * Counts single ``*`` markers in ``text``, excluding any ``*`` that is part
151	 * of a ``**`` (markdown bold). Used to detect WhatsApp-native ``*bold*``
152	 * pairs that the model emits when the platform context tells it to use
153	 * single-asterisk bold. Markdown bullets at line start (``^* ``) are also
154	 * excluded — they are not paired emphasis markers.
155	 */
156	function countSingleAsterisks(text: string): number {
157	  // Drop ``**`` first so the bold pairs don't double-count toward single-`*`.
158	  const noDouble = text.replaceAll("**", "");
159	  // Drop bullet-list ``*`` followed by a space at line start.
160	  const noBullets = noDouble.replaceAll(/^\*\s/gm, "");
161	  return (noBullets.match(/\*/g) ?? []).length;
162	}
163	
164	/**
165	 * Returns true if cutting ``text`` at index ``idx`` would land inside an
166	 * unclosed markdown emphasis span. We check the markers that actually bite us
167	 * in WhatsApp output: ``**bold**``, single-asterisk ``*bold*`` (the
168	 * WhatsApp-native bold the platform context steers the model toward), and
169	 * `` `inline code` ``. ``_`` and ``~`` are skipped because they appear in
170	 * identifiers/URLs and the false-positive rate would shrink chunks
171	 * pointlessly.
172	 *
173	 * The check is symmetric: an odd number of a marker in the prefix AND a
174	 * closing marker somewhere in the suffix means the cut would orphan one
175	 * half of the pair.
176	 */
177	function cutsInsideEmphasisSpan(text: string, idx: number): boolean {
178	  const prefixNarrative = stripFencedBlocks(text.slice(0, idx));
179	  const suffixNarrative = stripFencedBlocks(text.slice(idx));
180	
181	  const doubleAsteriskOpens = (prefixNarrative.match(/\*\*/g) ?? []).length;
182	  if (doubleAsteriskOpens % 2 === 1 && suffixNarrative.includes("**"))
183	    return true;
184	
185	  const singleAsteriskOpens = countSingleAsterisks(prefixNarrative);
186	  if (
187	    singleAsteriskOpens % 2 === 1 &&
188	    countSingleAsterisks(suffixNarrative) > 0
189	  )
190	    return true;
191	
192	  const inlineTickOpens = (prefixNarrative.match(/`/g) ?? []).length;
193	  if (inlineTickOpens % 2 === 1 && suffixNarrative.includes("`")) return true;
194	
195	  return false;
196	}
197	
198	/**
199	 * Aggregate predicate — true when the cut at ``idx`` would split any markdown
200	 * span (link or emphasis). Keeps {@link pickCutBoundary} short.
201	 */
202	function cutsInsideMarkdown(text: string, idx: number): boolean {
203	  return cutsInsideMarkdownLink(text, idx) || cutsInsideEmphasisSpan(text, idx);
204	}
205	
206	/**
207	 * Find the orphan single ``*`` to strip. Skips ``**`` (double-asterisk bold,
208	 * already handled separately) and ``* `` at line start (markdown bullet,
209	 * not an emphasis marker).
210	 *
211	 * @param scan - ``"tail"`` walks from the end (last orphan in chunk),
212	 *               ``"head"`` walks from the start (first orphan in next chunk).
213	 * @returns Index of the orphan ``*`` or -1 if none found.
214	 */
215	function findOrphanSingleAsterisk(text: string, scan: "tail" | "head"): number {
216	  const isBulletStart = (i: number): boolean => {
217	    const lineStart = text.lastIndexOf("\n", i - 1) + 1;
218	    // Ignore leading whitespace before checking ``*``
219	    let j = lineStart;
220	    while (j < i && (text[j] === " " || text[j] === "\t")) j++;
221	    return j === i && text[i + 1] === " ";
222	  };
223	
224	  const indices: number[] = [];
225	  for (let i = 0; i < text.length; i++) {
226	    if (text[i] !== "*") continue;
227	    if (text[i + 1] === "*") {
228	      i++; // skip second `*` of `**`
229	      continue;
230	    }
231	    if (text[i - 1] === "*") continue; // tail half of `**` (defensive)
232	    if (isBulletStart(i)) continue;
233	    indices.push(i);
234	  }
235	  if (indices.length === 0) return -1;
236	  return scan === "tail" ? (indices.at(-1) ?? -1) : indices[0];
237	}
238	
239	/**
240	 * Picks the best cut index ≤ ``limit`` for a chunk of ``text``. Prefers
241	 * paragraph (`\n\n`), then sentence enders, then word boundary, then a hard
242	 * cut at ``limit`` as a last resort. Boundaries that would split a markdown
243	 * link are skipped.
244	 *
245	 * The 50 %-of-limit floor avoids producing tiny fragments — if no decent
246	 * boundary exists in the second half of the window, we accept the hard cut
247	 * rather than emit a 200-char chunk on a 4000-char limit.
248	 */
249	function pickCutBoundary(text: string, limit: number): number {
250	  const window = text.slice(0, limit);
251	  const floor = limit * 0.5;
252	
253	  // 1. Paragraph break
254	  const paragraph = window.lastIndexOf("\n\n");
255	  if (paragraph >= floor && !cutsInsideMarkdown(text, paragraph)) {
256	    return paragraph;
257	  }
258	
259	  // 2. Sentence end (in priority order: ". ", "! ", "? ", "\n")
260	  let bestSentence = -1;
261	  for (const sep of [". ", "! ", "? ", "\n"]) {
262	    const idx = window.lastIndexOf(sep);
263	    if (idx < floor) continue;
264	    const cut = idx + sep.length;
265	    if (cut > bestSentence && !cutsInsideMarkdown(text, cut)) {
266	      bestSentence = cut;
267	    }
268	  }
269	  if (bestSentence > 0) return bestSentence;
270	
271	  // 3. Word boundary
272	  let space = window.lastIndexOf(" ");
273	  while (space >= floor) {
274	    if (!cutsInsideMarkdown(text, space + 1)) return space + 1;
275	    space = window.lastIndexOf(" ", space - 1);
276	  }
277	
278	  // 4. Hard cut as last resort
279	  return limit;
280	}
281	
282	function balanceDoubleAsterisks(
283	  chunk: string,
284	  next: string,
285	  chunkNarrative: string,
286	): [string, string] {
287	  const doubleOpens = (chunkNarrative.match(/\*\*/g) ?? []).length;
288	  if (doubleOpens % 2 !== 1) return [chunk, next];
289	  const lastIdx = chunk.lastIndexOf("**");
290	  if (lastIdx !== -1) {
291	    chunk = chunk.slice(0, lastIdx) + chunk.slice(lastIdx + 2);
292	  }
293	  const firstIdx = next.indexOf("**");
294	  if (firstIdx !== -1) {
295	    next = next.slice(0, firstIdx) + next.slice(firstIdx + 2);
296	  }
297	  return [chunk, next];
298	}
299	
300	function balanceSingleAsterisks(
301	  chunk: string,
302	  next: string,
303	  chunkNarrative: string,
304	): [string, string] {
305	  if (countSingleAsterisks(chunkNarrative) % 2 !== 1) return [chunk, next];
306	  const lastIdx = findOrphanSingleAsterisk(chunk, "tail");
307	  if (lastIdx !== -1) {
308	    chunk = chunk.slice(0, lastIdx) + chunk.slice(lastIdx + 1);
309	  }
310	  const firstIdx = findOrphanSingleAsterisk(next, "head");
311	  if (firstIdx !== -1) {
312	    next = next.slice(0, firstIdx) + next.slice(firstIdx + 1);
313	  }
314	  return [chunk, next];
315	}
316	
317	/**
318	 * Splits a long response into platform-sized chunks for delivery as multiple
319	 * messages instead of a single truncated bubble. Used by bot adapters so the
320	 * user receives the full content across as many bubbles as needed.
321	 *
322	 * The boundary search prefers paragraph breaks, then sentence enders, then
323	 * word boundaries, then a hard cut. Boundaries that would land inside a
324	 * markdown link `[text](url)` are skipped. If a chunk would end with an
325	 * unclosed code fence (```), the chunk is closed and the next chunk reopens
326	 * with the same fence so the markdown stays valid across bubbles.
327	 *
328	 * Each returned chunk is guaranteed to be ≤ the platform character limit
329	 * (after fence-balancing, the closing/reopening adds a small fixed overhead;
330	 * we leave headroom by reserving 8 chars for the fence pair).
331	 *
332	 * @param text - The full message text.
333	 * @param platform - The target platform (discord, slack, telegram, whatsapp).
334	 * @returns An array of chunks, in order, each ≤ the platform character limit.
335	 *   Returns ``[text]`` when ``text`` already fits.
336	 */
337	export function chunkResponse(
338	  text: string,
339	  platform: "discord" | "slack" | "telegram" | "whatsapp",
340	): string[] {
341	  const limit = PLATFORM_LIMITS[platform];
342	  if (text.length <= limit) return [text];
343	
344	  // Reserve space for code-fence balancing markers ("\n```" + "```\n") so a
345	  // chunk that closes/reopens a fence still fits inside the platform limit.
346	  const FENCE_HEADROOM = 8;
347	  const cutLimit = limit - FENCE_HEADROOM;
348	
349	  const chunks: string[] = [];
350	  let remaining = text;
351	
352	  while (remaining.length > limit) {
353	    const cutAt = pickCutBoundary(remaining, cutLimit);
354	    let chunk = remaining.slice(0, cutAt);
355	    let next = remaining.slice(cutAt);
356	
357	    const chunkNarrative = stripFencedBlocks(chunk);
358	    [chunk, next] = balanceDoubleAsterisks(chunk, next, chunkNarrative);
359	    [chunk, next] = balanceSingleAsterisks(chunk, next, chunkNarrative);
360	
361	    // Balance code fences across the cut: if the chunk has an odd number of
362	    // ``` it ends inside an open fence — close it here and reopen on the next
363	    // chunk so each bubble renders as valid markdown.
364	    const fenceCount = chunk.match(/```/g)?.length ?? 0;
365	    const insideFence = fenceCount % 2 === 1;
366	    if (insideFence) {
367	      chunk = `${chunk}\n\`\`\``;
368	      next = `\`\`\`\n${next}`;
369	    } else {
370	      // Cosmetic whitespace trim for narrative cuts only. We never trim when
371	      // the cut lands inside a fenced block, because leading whitespace there
372	      // is significant code indentation (Python, YAML) and trimming it would
373	      // produce broken code in the next bubble.
374	      chunk = chunk.trimEnd();
375	      next = next.trimStart();
376	    }
377	
378	    chunks.push(chunk);
379	    remaining = next;
380	  }
381	
382	  if (remaining.length > 0) chunks.push(remaining);
383	  return chunks.filter((c) => c.length > 0);
384	}
