1	/**
2	 * Shared @gaia/shared mock factory for bot adapter tests.
3	 *
4	 * All adapter tests mock @gaia/shared identically except for platform name,
5	 * STREAMING_DEFAULTS, and platform-specific converters. This factory avoids
6	 * duplicating the common ~40-line BaseBotAdapter stub across every test file.
7	 *
8	 * Usage in a test file:
9	 *
10	 *   vi.mock("@gaia/shared", async () => {
11	 *     const { makeGaiaSharedMock } = await import("../shared/mocks/gaiaSharedBase");
12	 *     return makeGaiaSharedMock("whatsapp", {
13	 *       streamingDefaults: { whatsapp: { editIntervalMs: 2000, streaming: false, platform: "whatsapp" } },
14	 *       converters: { convertToWhatsAppMarkdown: vi.fn((t: string) => t) },
15	 *       defaultRichMarkdown: "*GAIA Help*\nUse /gaia to chat",
16	 *     });
17	 *   });
18	 */
19	
20	import { vi } from "vitest";
21	
22	interface GaiaSharedMockOptions {
23	  /** Per-platform streaming configuration object */
24	  streamingDefaults: Record<string, unknown>;
