#!/usr/bin/env node
/**
 * Estimates SonarCloud's "Duplication on New Code" metric locally.
 *
 * Why this exists: jscpd's own `threshold` is a percentage over the WHOLE repo,
 * so it is ~0.8% and never trips for a single PR. SonarCloud instead gates on
 * duplicated lines among NEW code (the diff vs the base branch). A whole-repo
 * pass therefore tells you nothing about whether SonarCloud's gate will pass.
 *
 * This script reproduces SonarCloud's denominator: it runs jscpd, then maps
 * every detected clone's line ranges onto the lines this branch ADDED vs the
 * base branch, and reports `duplicated new lines / new lines`.
 *
 * IMPORTANT: this is an ESTIMATE. jscpd's tokenizer and SonarCloud's are not
 * identical, and SonarCloud's "new code" definition is configurable. Treat the
 * number as a fast pre-push signal; SonarCloud remains the source of truth.
 *
 * Env:
 *   JSCPD_BASE            base ref (default: origin/develop)
 *   JSCPD_NEW_THRESHOLD   gate percentage (default: 3)
 *   JSCPD_NEW_ADVISORY=1  never exit non-zero (print only)
 */
import { execSync } from "node:child_process";
import { mkdtempSync, readFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";

const BASE = process.env.JSCPD_BASE || "origin/develop";
const THRESHOLD = Number(process.env.JSCPD_NEW_THRESHOLD || "3");
const ADVISORY = process.env.JSCPD_NEW_ADVISORY === "1";

const sh = (cmd) => execSync(cmd, { encoding: "utf8", maxBuffer: 64 * 1024 * 1024 });

const repoRoot = sh("git rev-parse --show-toplevel").trim();
const rel = (p) =>
  p.startsWith(`${repoRoot}/`) ? p.slice(repoRoot.length + 1) : p;

let base;
try {
  base = sh(`git merge-base ${BASE} HEAD`).trim();
} catch {
  // Shallow clone or no common ancestor: fall back to the base ref tip.
  try {
    base = sh(`git rev-parse --verify ${BASE}^{commit}`).trim();
  } catch {
    console.error(
      `jscpd-new-code: could not resolve base "${BASE}". ` +
        `Fetch it (git fetch origin <branch>) or set JSCPD_BASE.`,
    );
    process.exit(2);
  }
}

// Lines added on the new side, per file (working tree vs base, so uncommitted
// changes count too — this is meant to run before you push).
const added = new Map();
let currentFile = null;
for (const line of sh(`git diff --unified=0 ${base}`).split("\n")) {
  if (line.startsWith("+++ ")) {
    const p = line.slice(4).trim();
    currentFile = p === "/dev/null" ? null : p.replace(/^b\//, "");
  } else if (line.startsWith("@@") && currentFile) {
    const m = /\+(\d+)(?:,(\d+))?/.exec(line);
    if (m) {
      const start = Number(m[1]);
      const count = m[2] === undefined ? 1 : Number(m[2]);
      let set = added.get(currentFile);
      if (!set) added.set(currentFile, (set = new Set()));
      for (let i = 0; i < count; i++) set.add(start + i);
    }
  }
}

// Run jscpd (reuses .jscpd.json) and load the JSON report.
const outDir = mkdtempSync(join(tmpdir(), "jscpd-newcode-"));
sh(`pnpm exec jscpd --reporters json --output ${outDir} --silent .`);
const report = JSON.parse(
  readFileSync(join(outDir, "jscpd-report.json"), "utf8"),
);

// Files jscpd analyzed — defines the denominator scope, like SonarCloud.
const analyzed = new Set();
for (const fmt of Object.values(report.statistics?.formats ?? {})) {
  for (const f of Object.keys(fmt.sources ?? {})) analyzed.add(rel(f));
}

// Lines covered by at least one clone, per file.
const covered = new Map();
const cover = (f, s, e) => {
  let set = covered.get(f);
  if (!set) covered.set(f, (set = new Set()));
  for (let i = s; i <= e; i++) set.add(i);
};
for (const d of report.duplicates ?? []) {
  cover(rel(d.firstFile.name), d.firstFile.start, d.firstFile.end);
  cover(rel(d.secondFile.name), d.secondFile.start, d.secondFile.end);
}

// New lines that fall inside a duplicated block, restricted to analyzed files.
let newLines = 0;
let dupNewLines = 0;
const offenders = [];
for (const [file, addedSet] of added) {
  if (!analyzed.has(file)) continue;
  newLines += addedSet.size;
  const cov = covered.get(file);
  if (!cov) continue;
  let n = 0;
  for (const ln of addedSet) if (cov.has(ln)) n++;
  if (n > 0) {
    dupNewLines += n;
    offenders.push([file, n]);
  }
}

const density = newLines === 0 ? 0 : (dupNewLines / newLines) * 100;
console.log(
  `New-code duplication (estimate vs ${BASE}): ${density.toFixed(2)}%  ` +
    `(${dupNewLines}/${newLines} new lines in duplicated blocks)`,
);
if (offenders.length) {
  console.log("Files contributing duplicated new lines:");
  for (const [f, n] of offenders.sort((a, b) => b[1] - a[1])) {
    console.log(`  ${String(n).padStart(4)}  ${f}`);
  }
}
console.log(
  `Gate: <= ${THRESHOLD}% on new code (estimate; SonarCloud is authoritative).`,
);

if (density > THRESHOLD && !ADVISORY) {
  console.error(
    `\njscpd-new-code: estimated ${density.toFixed(2)}% exceeds ${THRESHOLD}%. ` +
      `Dedupe the files above, or set JSCPD_NEW_ADVISORY=1 to warn only.`,
  );
  process.exit(1);
}

